diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 24a166906f1f..7ad955735495 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1236,23 +1236,34 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Rounding is done by adding -1 if the dividend (X) is negative and has any
   // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
   // sext (icmp ugt (X & (DivC - 1)), SMIN)
-  const APInt *MaskC;
+  // Or equivalently for DivC=2: sext (icmp eq (X & (SMin | 1)), SMin | 1)
+  const APInt *MaskC, *CmpC;
   ICmpInst::Predicate Pred;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_APInt(CmpC)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
-  if (*MaskC != (SMin | (*DivC - 1)))
-    return nullptr;
-
-  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
-  return BinaryOperator::CreateAShr(
-      X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
+  APInt ExpectedMask = SMin | (*DivC - 1);
+  
+  // Check if this is the UGT pattern: (X & Mask) ugt SMin
+  if (Pred == ICmpInst::ICMP_UGT && *MaskC == ExpectedMask && *CmpC == SMin) {
+    // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
+    return BinaryOperator::CreateAShr(
+        X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
+  }
+  
+  // Check if this is the EQ pattern: (X & Mask) eq Mask
+  // This is only equivalent to the UGT pattern when DivC == 2 (single low bit)
+  if (Pred == ICmpInst::ICMP_EQ && *MaskC == ExpectedMask && *CmpC == ExpectedMask &&
+      *DivC == 2) {
+    // (X / 2) + sext ((X & (SMin | 1)) == (SMin | 1)) --> X >>s 1
+    return BinaryOperator::CreateAShr(X, ConstantInt::get(Add.getType(), 1));
+  }
+  
+  return nullptr;
 }
-
 Instruction *InstCombinerImpl::
     canonicalizeCondSignextOfHighBitExtractToSignextHighBitExtract(
         BinaryOperator &I) {

